/* VCD dumping routines */

unsigned int MOD_mkEpochManager::dump_VCD_defs(unsigned int levels)
{
  vcd_write_scope_start(sim_hdl, inst_name);
  vcd_num = vcd_reserve_ids(sim_hdl, 24u);
  unsigned int num = vcd_num;
  for (unsigned int clk = 0u; clk < bk_num_clocks(sim_hdl); ++clk)
    vcd_add_clock_def(sim_hdl, this, bk_clock_name(sim_hdl, clk), bk_clock_vcd_num(sim_hdl, clk));
  vcd_write_def(sim_hdl, bk_clock_vcd_num(sim_hdl, __clk_handle_0), "CLK", 1u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "IF_updatePrevEn_0_lat_0_whas_THEN_updatePrevEn_ETC___d22", 1u);
  vcd_write_def(sim_hdl, num++, "RST_N", 1u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "checkedEpoch__h3097", 4u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "next_epoch__h81", 4u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "updatePrevEn_0_lat_0_wget_BIT_4___d20", 1u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "updatePrevEn_0_lat_0_wget____d4", 5u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "updatePrevEn_0_lat_0_whas____d3", 1u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "updatePrevEn_0_rl_BIT_4___d21", 1u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "updatePrevEn_0_rl___d5", 5u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "updatePrevEn_1_lat_0_wget____d11", 5u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "updatePrevEn_1_lat_0_whas____d10", 1u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "updatePrevEn_1_rl___d12", 5u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "x__h3367", 4u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "x__h3370", 4u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "x__h729", 4u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "x__h730", 4u);
  num = INST_curr_epoch.dump_VCD_defs(num);
  num = INST_prev_checked_epoch.dump_VCD_defs(num);
  num = INST_updatePrevEn_0_lat_0.dump_VCD_defs(num);
  num = INST_updatePrevEn_0_lat_1.dump_VCD_defs(num);
  num = INST_updatePrevEn_0_rl.dump_VCD_defs(num);
  num = INST_updatePrevEn_1_lat_0.dump_VCD_defs(num);
  num = INST_updatePrevEn_1_lat_1.dump_VCD_defs(num);
  num = INST_updatePrevEn_1_rl.dump_VCD_defs(num);
  vcd_write_scope_end(sim_hdl);
  return num;
}

void MOD_mkEpochManager::dump_VCD(tVCDDumpType dt, unsigned int levels, MOD_mkEpochManager &backing)
{
  vcd_defs(dt, backing);
  vcd_prims(dt, backing);
}

void MOD_mkEpochManager::vcd_defs(tVCDDumpType dt, MOD_mkEpochManager &backing)
{
  unsigned int num = vcd_num;
  if (dt == VCD_DUMP_XS)
  {
    vcd_write_x(sim_hdl, num++, 1u);
    vcd_write_x(sim_hdl, num++, 1u);
    vcd_write_x(sim_hdl, num++, 4u);
    vcd_write_x(sim_hdl, num++, 4u);
    vcd_write_x(sim_hdl, num++, 1u);
    vcd_write_x(sim_hdl, num++, 5u);
    vcd_write_x(sim_hdl, num++, 1u);
    vcd_write_x(sim_hdl, num++, 1u);
    vcd_write_x(sim_hdl, num++, 5u);
    vcd_write_x(sim_hdl, num++, 5u);
    vcd_write_x(sim_hdl, num++, 1u);
    vcd_write_x(sim_hdl, num++, 5u);
    vcd_write_x(sim_hdl, num++, 4u);
    vcd_write_x(sim_hdl, num++, 4u);
    vcd_write_x(sim_hdl, num++, 4u);
    vcd_write_x(sim_hdl, num++, 4u);
  }
  else
    if (dt == VCD_DUMP_CHANGES)
    {
      if ((backing.DEF_IF_updatePrevEn_0_lat_0_whas_THEN_updatePrevEn_ETC___d22) != DEF_IF_updatePrevEn_0_lat_0_whas_THEN_updatePrevEn_ETC___d22)
      {
	vcd_write_val(sim_hdl, num, DEF_IF_updatePrevEn_0_lat_0_whas_THEN_updatePrevEn_ETC___d22, 1u);
	backing.DEF_IF_updatePrevEn_0_lat_0_whas_THEN_updatePrevEn_ETC___d22 = DEF_IF_updatePrevEn_0_lat_0_whas_THEN_updatePrevEn_ETC___d22;
      }
      ++num;
      if ((backing.PORT_RST_N) != PORT_RST_N)
      {
	vcd_write_val(sim_hdl, num, PORT_RST_N, 1u);
	backing.PORT_RST_N = PORT_RST_N;
      }
      ++num;
      if ((backing.DEF_checkedEpoch__h3097) != DEF_checkedEpoch__h3097)
      {
	vcd_write_val(sim_hdl, num, DEF_checkedEpoch__h3097, 4u);
	backing.DEF_checkedEpoch__h3097 = DEF_checkedEpoch__h3097;
      }
      ++num;
      if ((backing.DEF_next_epoch__h81) != DEF_next_epoch__h81)
      {
	vcd_write_val(sim_hdl, num, DEF_next_epoch__h81, 4u);
	backing.DEF_next_epoch__h81 = DEF_next_epoch__h81;
      }
      ++num;
      if ((backing.DEF_updatePrevEn_0_lat_0_wget_BIT_4___d20) != DEF_updatePrevEn_0_lat_0_wget_BIT_4___d20)
      {
	vcd_write_val(sim_hdl, num, DEF_updatePrevEn_0_lat_0_wget_BIT_4___d20, 1u);
	backing.DEF_updatePrevEn_0_lat_0_wget_BIT_4___d20 = DEF_updatePrevEn_0_lat_0_wget_BIT_4___d20;
      }
      ++num;
      if ((backing.DEF_updatePrevEn_0_lat_0_wget____d4) != DEF_updatePrevEn_0_lat_0_wget____d4)
      {
	vcd_write_val(sim_hdl, num, DEF_updatePrevEn_0_lat_0_wget____d4, 5u);
	backing.DEF_updatePrevEn_0_lat_0_wget____d4 = DEF_updatePrevEn_0_lat_0_wget____d4;
      }
      ++num;
      if ((backing.DEF_updatePrevEn_0_lat_0_whas____d3) != DEF_updatePrevEn_0_lat_0_whas____d3)
      {
	vcd_write_val(sim_hdl, num, DEF_updatePrevEn_0_lat_0_whas____d3, 1u);
	backing.DEF_updatePrevEn_0_lat_0_whas____d3 = DEF_updatePrevEn_0_lat_0_whas____d3;
      }
      ++num;
      if ((backing.DEF_updatePrevEn_0_rl_BIT_4___d21) != DEF_updatePrevEn_0_rl_BIT_4___d21)
      {
	vcd_write_val(sim_hdl, num, DEF_updatePrevEn_0_rl_BIT_4___d21, 1u);
	backing.DEF_updatePrevEn_0_rl_BIT_4___d21 = DEF_updatePrevEn_0_rl_BIT_4___d21;
      }
      ++num;
      if ((backing.DEF_updatePrevEn_0_rl___d5) != DEF_updatePrevEn_0_rl___d5)
      {
	vcd_write_val(sim_hdl, num, DEF_updatePrevEn_0_rl___d5, 5u);
	backing.DEF_updatePrevEn_0_rl___d5 = DEF_updatePrevEn_0_rl___d5;
      }
      ++num;
      if ((backing.DEF_updatePrevEn_1_lat_0_wget____d11) != DEF_updatePrevEn_1_lat_0_wget____d11)
      {
	vcd_write_val(sim_hdl, num, DEF_updatePrevEn_1_lat_0_wget____d11, 5u);
	backing.DEF_updatePrevEn_1_lat_0_wget____d11 = DEF_updatePrevEn_1_lat_0_wget____d11;
      }
      ++num;
      if ((backing.DEF_updatePrevEn_1_lat_0_whas____d10) != DEF_updatePrevEn_1_lat_0_whas____d10)
      {
	vcd_write_val(sim_hdl, num, DEF_updatePrevEn_1_lat_0_whas____d10, 1u);
	backing.DEF_updatePrevEn_1_lat_0_whas____d10 = DEF_updatePrevEn_1_lat_0_whas____d10;
      }
      ++num;
      if ((backing.DEF_updatePrevEn_1_rl___d12) != DEF_updatePrevEn_1_rl___d12)
      {
	vcd_write_val(sim_hdl, num, DEF_updatePrevEn_1_rl___d12, 5u);
	backing.DEF_updatePrevEn_1_rl___d12 = DEF_updatePrevEn_1_rl___d12;
      }
      ++num;
      if ((backing.DEF_x__h3367) != DEF_x__h3367)
      {
	vcd_write_val(sim_hdl, num, DEF_x__h3367, 4u);
	backing.DEF_x__h3367 = DEF_x__h3367;
      }
      ++num;
      if ((backing.DEF_x__h3370) != DEF_x__h3370)
      {
	vcd_write_val(sim_hdl, num, DEF_x__h3370, 4u);
	backing.DEF_x__h3370 = DEF_x__h3370;
      }
      ++num;
      if ((backing.DEF_x__h729) != DEF_x__h729)
      {
	vcd_write_val(sim_hdl, num, DEF_x__h729, 4u);
	backing.DEF_x__h729 = DEF_x__h729;
      }
      ++num;
      if ((backing.DEF_x__h730) != DEF_x__h730)
      {
	vcd_write_val(sim_hdl, num, DEF_x__h730, 4u);
	backing.DEF_x__h730 = DEF_x__h730;
      }
      ++num;
    }
    else
    {
      vcd_write_val(sim_hdl, num++, DEF_IF_updatePrevEn_0_lat_0_whas_THEN_updatePrevEn_ETC___d22, 1u);
      backing.DEF_IF_updatePrevEn_0_lat_0_whas_THEN_updatePrevEn_ETC___d22 = DEF_IF_updatePrevEn_0_lat_0_whas_THEN_updatePrevEn_ETC___d22;
      vcd_write_val(sim_hdl, num++, PORT_RST_N, 1u);
      backing.PORT_RST_N = PORT_RST_N;
      vcd_write_val(sim_hdl, num++, DEF_checkedEpoch__h3097, 4u);
      backing.DEF_checkedEpoch__h3097 = DEF_checkedEpoch__h3097;
      vcd_write_val(sim_hdl, num++, DEF_next_epoch__h81, 4u);
      backing.DEF_next_epoch__h81 = DEF_next_epoch__h81;
      vcd_write_val(sim_hdl, num++, DEF_updatePrevEn_0_lat_0_wget_BIT_4___d20, 1u);
      backing.DEF_updatePrevEn_0_lat_0_wget_BIT_4___d20 = DEF_updatePrevEn_0_lat_0_wget_BIT_4___d20;
      vcd_write_val(sim_hdl, num++, DEF_updatePrevEn_0_lat_0_wget____d4, 5u);
      backing.DEF_updatePrevEn_0_lat_0_wget____d4 = DEF_updatePrevEn_0_lat_0_wget____d4;
      vcd_write_val(sim_hdl, num++, DEF_updatePrevEn_0_lat_0_whas____d3, 1u);
      backing.DEF_updatePrevEn_0_lat_0_whas____d3 = DEF_updatePrevEn_0_lat_0_whas____d3;
      vcd_write_val(sim_hdl, num++, DEF_updatePrevEn_0_rl_BIT_4___d21, 1u);
      backing.DEF_updatePrevEn_0_rl_BIT_4___d21 = DEF_updatePrevEn_0_rl_BIT_4___d21;
      vcd_write_val(sim_hdl, num++, DEF_updatePrevEn_0_rl___d5, 5u);
      backing.DEF_updatePrevEn_0_rl___d5 = DEF_updatePrevEn_0_rl___d5;
      vcd_write_val(sim_hdl, num++, DEF_updatePrevEn_1_lat_0_wget____d11, 5u);
      backing.DEF_updatePrevEn_1_lat_0_wget____d11 = DEF_updatePrevEn_1_lat_0_wget____d11;
      vcd_write_val(sim_hdl, num++, DEF_updatePrevEn_1_lat_0_whas____d10, 1u);
      backing.DEF_updatePrevEn_1_lat_0_whas____d10 = DEF_updatePrevEn_1_lat_0_whas____d10;
      vcd_write_val(sim_hdl, num++, DEF_updatePrevEn_1_rl___d12, 5u);
      backing.DEF_updatePrevEn_1_rl___d12 = DEF_updatePrevEn_1_rl___d12;
      vcd_write_val(sim_hdl, num++, DEF_x__h3367, 4u);
      backing.DEF_x__h3367 = DEF_x__h3367;
      vcd_write_val(sim_hdl, num++, DEF_x__h3370, 4u);
      backing.DEF_x__h3370 = DEF_x__h3370;
      vcd_write_val(sim_hdl, num++, DEF_x__h729, 4u);
      backing.DEF_x__h729 = DEF_x__h729;
      vcd_write_val(sim_hdl, num++, DEF_x__h730, 4u);
      backing.DEF_x__h730 = DEF_x__h730;
    }
}

void MOD_mkEpochManager::vcd_prims(tVCDDumpType dt, MOD_mkEpochManager &backing)
{
  INST_curr_epoch.dump_VCD(dt, backing.INST_curr_epoch);
  INST_prev_checked_epoch.dump_VCD(dt, backing.INST_prev_checked_epoch);
  INST_updatePrevEn_0_lat_0.dump_VCD(dt, backing.INST_updatePrevEn_0_lat_0);
  INST_updatePrevEn_0_lat_1.dump_VCD(dt, backing.INST_updatePrevEn_0_lat_1);
  INST_updatePrevEn_0_rl.dump_VCD(dt, backing.INST_updatePrevEn_0_rl);
  INST_updatePrevEn_1_lat_0.dump_VCD(dt, backing.INST_updatePrevEn_1_lat_0);
  INST_updatePrevEn_1_lat_1.dump_VCD(dt, backing.INST_updatePrevEn_1_lat_1);
  INST_updatePrevEn_1_rl.dump_VCD(dt, backing.INST_updatePrevEn_1_rl);
}
